52	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUM_BY_TYPE));
53	
54	const validateItems = (items: Item[]): void => {
55	  for (const item of items) {
56	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
57	      throw new Error(`unknown item type: ${item.type}`);
58	    }
59	  }
60	};
