67	  if (item.cursed) s += base * CURSE_SURCHARGE_RATE;
68	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
69	    s += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
70	  }
71	  s += base * FIRST_INSURANCE_RATE;
