100	const itemSurchargeTotal = (items: Item[]): number =>
101	  mainItemsOf(items).reduce((sum, item) => sum + itemSurcharges(item), 0);
102	
103	const quotePremium = (items: Item[], customer: Customer, priorQuotes: number): number => {
104	  const policyBaseAmount = policyBase(items);
105	  const surcharges = itemSurchargeTotal(items);
106	  let policyAdjustment = 0;
107	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
108	    policyAdjustment -= policyBaseAmount * LOYALTY_DISCOUNT_RATE;
109	  }
110	  if (priorQuotes >= 1) {
111	    policyAdjustment -= policyBaseAmount * FOLLOWUP_DISCOUNT_RATE;
112	  }
113	  const total = policyBaseAmount + surcharges + policyAdjustment + PROCESSING_FEE;
114	  return Math.ceil(total);
115	};
