120	type Policy = { items: Item[]; capRemaining: number };
121	
122	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
124	
125	const reimbursableAmount = (item: Item, damageAmount: number): number => {
126	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
127	    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
128	  }
129	  return damageAmount;
130	};
