132	const findInsuredItem = (policy: Policy, itemType: string): Item =>
133	  policy.items.find((item) => item.type === itemType)!;
134	
135	const damagePayout = (policy: Policy, damage: Damage): number => {
136	  const item = findInsuredItem(policy, damage.itemType);
137	  return Math.max(0, reimbursableAmount(item, damage.amount) - DEDUCTIBLE);
138	};
139	
140	const validateDamages = (damages: Damage[]): void => {
141	  for (const damage of damages) {
142	    if (damage.amount < 0) {
143	      throw new Error(`damage amount must be non-negative: ${damage.amount}`);
144	    }
145	  }
146	};
