148	const validateDamagesAgainstPolicy = (policy: Policy, damages: Damage[]): void => {
149	  const insuredCounts = new Map<string, number>();
150	  for (const item of policy.items) {
151	    insuredCounts.set(item.type, (insuredCounts.get(item.type) ?? 0) + 1);
152	  }
153	  const damageCounts = new Map<string, number>();
154	  for (const damage of damages) {
