167	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
168	  validateDamages(incident.damages);
169	  validateDamagesAgainstPolicy(policy, incident.damages);
170	  const claimedAmount = incident.damages
171	    .map((damage) => damagePayout(policy, damage))
172	    .reduce((sum, amount) => sum + amount, 0);
173	  const payout = Math.floor(Math.min(claimedAmount, policy.capRemaining));
174	  policy.capRemaining -= payout;
175	  return { payout, remainingCap: policy.capRemaining };
176	};
177	
178	const openPolicy = (items: Item[]): Policy => ({
179	  items,
180	  capRemaining: insuranceSum(items) * CAP_MULTIPLIER,
181	});
