183	export const runScenario = (input: Scenario): { results: StepResult[] } => {
184	  const policies: Policy[] = [];
185	  let quoteCount = 0;
186	  const handleStep = (step: Step): StepResult => {
187	    if (step.op === "quote") {
188	      validateItems(step.items);
189	      const premium = quotePremium(step.items, input.customer, quoteCount);
190	      quoteCount++;
191	      policies.push(openPolicy(step.items));
192	      return { premium };
193	    }
194	    return processClaim(policies[step.policy], step.incident);
195	  };
196	  return { results: input.steps.map(handleStep) };
197	};
